#!/usr/bin/env bashset -euo pipefailALEMBIC_CMD="uv run alembic"API_PORT=8000echo "Выполняю миграции: upgrade head"${ALEMBIC_CMD} upgrade headecho "Запускаю сервисы..."uv run -m src.main &MAIN_PID=$!uv run uvicorn src.server:app --host 0.0.0.0 --port ${API_PORT} &UVICORN_PID=$!trap 'kill -TERM ${MAIN_PID} ${UVICORN_PID} 2>/dev/null || true' TERM INTwait ${MAIN_PID} ${UVICORN_PID}